-- 미디어 규격 + Threads 검수 절차 (상세). 줄바꿈은 E-string \n.

INSERT INTO faqs (category, question, answer, sort_order, created_at, updated_at) VALUES
-- 미디어 규격
('미디어 규격', '첨부 이미지 규격(형식·용량·비율)은 어떻게 되나요?', E'Threads 이미지 권장 사양입니다.\n- 형식: JPEG 또는 PNG\n- 용량: 최대 8MB\n- 너비: 최소 320px, 권장 최대 1440px\n- 가로세로비: 약 0.566(세로 9:16) ~ 1.91(가로) 사이\n- 색공간: sRGB 권장\n비율을 벗어나면 Threads에서 잘리거나 거부될 수 있어요. 정확한 최신 수치는 Meta 공식 Threads API 문서를 함께 확인하세요.', 110, now(), now()),
('미디어 규격', '영상(동영상) 규격은 어떻게 되나요?', E'Threads 동영상 권장 사양입니다.\n- 형식: MP4 또는 MOV\n- 코덱: 영상 H.264/HEVC, 오디오 AAC\n- 길이: 최대 약 5분(300초)\n- 용량: 최대 약 1GB\n- 가로세로비: 0.01:1 ~ 10:1 (권장 9:16 ~ 1.91:1)\n- 프레임레이트: 약 23~60fps, 너비 최대 1920px 권장\n수치는 플랫폼 정책에 따라 바뀔 수 있으니 Meta 공식 문서를 함께 확인하세요.', 111, now(), now()),
('미디어 규격', '지금 앱에서 영상도 올릴 수 있나요?', E'현재 PostFlow는 이미지 첨부를 지원합니다. 영상은 Threads 플랫폼 차원에서는 가능하지만 앱 UI 연동은 추후 제공 예정이에요. 영상이 필요하면 deerkrg@gmail.com 으로 알려주시면 우선순위에 반영하겠습니다.', 112, now(), now()),
('미디어 규격', '이미지가 흐리게/잘려 보여요.', E'1) 권장 너비(최대 1440px) 이상 고해상도로 올리되 8MB를 넘지 마세요.\n2) 가로세로비를 권장 범위(세로 9:16 ~ 가로 1.91)로 맞추면 잘림이 줄어요.\n3) 업로드 후 상세 모달의 미리보기로 실제 노출을 확인하세요.', 113, now(), now()),

-- Threads 검수 절차
('Threads 검수', '왜 나/내 지인만 발행이 되고 일반 사용자는 안 되나요?', E'Meta 앱이 "개발 모드"이면 앱에 등록된 테스터 계정만 연결·발행할 수 있습니다. 일반 사용자가 쓰게 하려면 Meta 앱 검수(App Review)를 통과해 권한을 정식 승인받아야 합니다.', 120, now(), now()),
('Threads 검수', 'Threads 앱 검수는 어떤 절차인가요?', E'대략 이런 흐름입니다.\n1) Meta 개발자 센터에서 앱 생성 + 비즈니스 인증\n2) 개인정보 처리방침 URL, 데이터 삭제 콜백/안내 등록\n3) Threads use-case에 Redirect Callback URL(HTTPS) 등록\n4) 필요한 권한(threads_basic, threads_content_publish, threads_manage_insights 등)에 대해 사용 사례 설명 + 시연 영상(스크린캐스트) 첨부\n5) 검수 제출 → 검토(수일~수주) → 승인\n승인 후에는 일반 사용자도 Threads 연결·발행이 가능합니다.', 121, now(), now()),
('Threads 검수', '검수 제출 전에 무엇을 준비해야 하나요?', E'체크리스트:\n- 고정 HTTPS 도메인(콜백/정책 URL용)\n- 개인정보 처리방침 + 서비스 약관 공개 페이지\n- 데이터 삭제 요청 처리 경로(콜백 또는 안내)\n- 각 권한의 실제 사용 흐름을 보여주는 시연 영상\n- 앱 아이콘/이름/설명\nPostFlow는 약관·개인정보 링크, 데이터 삭제/디오소라이즈 콜백 엔드포인트를 이미 갖추고 있어 제출 준비가 수월합니다.', 122, now(), now()),
('Threads 검수', '검수에 보통 얼마나 걸리나요?', E'Meta 검토는 보통 수일에서 수 주가 걸립니다. 반려되면 사유에 맞춰 보완 후 재제출하면 됩니다. 검수와 무관하게, 본인/테스터 계정으로는 개발 모드에서도 바로 발행을 테스트할 수 있어요.', 123, now(), now()),
('Threads 검수', '검수 없이 먼저 써볼 수 있나요?', E'네. 내 Threads 계정(또는 테스터로 추가한 계정)을 연결하면 개발 모드에서도 생성·예약·발행을 모두 테스트할 수 있습니다. 외부 사용자에게 공개해 서비스로 운영할 때만 검수 통과가 필요합니다.', 124, now(), now());
